// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package policy

import (
	"bytes"
	"context"
	"log/slog"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

func TestPolicyAuditLoggerCreation(t *testing.T) {
	logger := slog.Default()
	pal := NewPolicyAuditLogger(logger, slog.LevelInfo)

	assert.NotNil(t, pal)
	assert.Equal(t, slog.LevelInfo, pal.GetLogLevel())
}

func TestPolicyAuditLoggerWithNilLogger(t *testing.T) {
	pal := NewPolicyAuditLogger(nil, slog.LevelDebug)

	assert.NotNil(t, pal)
	// Should have a default logger
	assert.NotNil(t, pal.logger)
}

func TestLogDecision(t *testing.T) {
	// Create a buffer to capture log output
	buf := new(bytes.Buffer)
	opts := &slog.HandlerOptions{Level: slog.LevelDebug}
	handler := slog.NewTextHandler(buf, opts)
	logger := slog.New(handler)

	pal := NewPolicyAuditLogger(logger, slog.LevelInfo)

	testID := identity.NumericIdentity(1000)
	pal.LogDecision(testID, "test-policy", "ALLOW", "matched selector")

	output := buf.String()
	assert.NotEmpty(t, output)
	assert.Contains(t, output, "policy decision")
	assert.Contains(t, output, "1000")
	assert.Contains(t, output, "test-policy")
	assert.Contains(t, output, "ALLOW")
	assert.Contains(t, output, "matched selector")
}

func TestLogDecisionWithDenyVerdict(t *testing.T) {
	buf := new(bytes.Buffer)
	opts := &slog.HandlerOptions{Level: slog.LevelDebug}
	handler := slog.NewTextHandler(buf, opts)
	logger := slog.New(handler)

	pal := NewPolicyAuditLogger(logger, slog.LevelInfo)

	testID := identity.NumericIdentity(2000)
	pal.LogDecision(testID, "deny-policy", "DENY", "explicit deny rule")

	output := buf.String()
	assert.NotEmpty(t, output)
	assert.Contains(t, output, "policy decision")
	assert.Contains(t, output, "DENY")
	assert.Contains(t, output, "explicit deny rule")
}

func TestLogEvaluation(t *testing.T) {
	buf := new(bytes.Buffer)
	opts := &slog.HandlerOptions{Level: slog.LevelDebug}
	handler := slog.NewTextHandler(buf, opts)
	logger := slog.New(handler)

	pal := NewPolicyAuditLogger(logger, slog.LevelInfo)
	ctx := context.Background()

	pal.LogEvaluation(ctx, "test-policy-key", nil, "test-result")

	output := buf.String()
	assert.NotEmpty(t, output)
	assert.Contains(t, output, "policy evaluation")
	assert.Contains(t, output, "test-policy-key")
	assert.Contains(t, output, "test-result")
}

func TestLogEvaluationWithSelectorCache(t *testing.T) {
	buf := new(bytes.Buffer)
	opts := &slog.HandlerOptions{Level: slog.LevelDebug}
	handler := slog.NewTextHandler(buf, opts)
	logger := slog.New(handler)

	pal := NewPolicyAuditLogger(logger, slog.LevelInfo)
	ctx := context.Background()

	// Create a minimal mock SelectorCache (we pass a real one but just check it's logged)
	pal.LogEvaluation(ctx, "policy-with-cache", nil, map[string]interface{}{"key": "value"})

	output := buf.String()
	assert.NotEmpty(t, output)
	assert.Contains(t, output, "policy evaluation")
}

func TestSetLogLevel(t *testing.T) {
	pal := NewPolicyAuditLogger(slog.Default(), slog.LevelInfo)

	assert.Equal(t, slog.LevelInfo, pal.GetLogLevel())

	pal.SetLogLevel(slog.LevelDebug)
	assert.Equal(t, slog.LevelDebug, pal.GetLogLevel())

	pal.SetLogLevel(slog.LevelWarn)
	assert.Equal(t, slog.LevelWarn, pal.GetLogLevel())
}

func TestLogDecisionThreadSafety(t *testing.T) {
	buf := new(bytes.Buffer)
	opts := &slog.HandlerOptions{Level: slog.LevelDebug}
	handler := slog.NewTextHandler(buf, opts)
	logger := slog.New(handler)

	pal := NewPolicyAuditLogger(logger, slog.LevelInfo)

	// Simulate concurrent access
	done := make(chan bool, 10)
	for i := 0; i < 10; i++ {
		go func(id int) {
			testID := identity.NumericIdentity(1000 + id)
			pal.LogDecision(testID, "policy", "ALLOW", "test")
			done <- true
		}(i)
	}

	// Wait for all goroutines
	for i := 0; i < 10; i++ {
		<-done
	}

	output := buf.String()
	assert.NotEmpty(t, output)
}

func TestLogEvaluationWithContext(t *testing.T) {
	buf := new(bytes.Buffer)
	opts := &slog.HandlerOptions{Level: slog.LevelDebug}
	handler := slog.NewTextHandler(buf, opts)
	logger := slog.New(handler)

	pal := NewPolicyAuditLogger(logger, slog.LevelInfo)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	pal.LogEvaluation(ctx, "test-policy-key", nil, "result")

	output := buf.String()
	assert.NotEmpty(t, output)
	assert.Contains(t, output, "policy evaluation")
}

func TestLogDecisionWithFieldConsistency(t *testing.T) {
	buf := new(bytes.Buffer)
	opts := &slog.HandlerOptions{Level: slog.LevelDebug}
	handler := slog.NewTextHandler(buf, opts)
	logger := slog.New(handler)

	pal := NewPolicyAuditLogger(logger, slog.LevelInfo)

	// Log multiple decisions and verify they contain consistent fields
	decisions := []struct {
		id     identity.NumericIdentity
		policy string
		verdict string
		reason string
	}{
		{1000, "policy1", "ALLOW", "reason1"},
		{2000, "policy2", "DENY", "reason2"},
		{3000, "policy3", "ALLOW", "reason3"},
	}

	for _, d := range decisions {
		pal.LogDecision(d.id, d.policy, d.verdict, d.reason)
	}

	output := buf.String()
	assert.NotEmpty(t, output)

	// Verify all decisions were logged
	for _, d := range decisions {
		assert.Contains(t, output, d.policy)
		assert.Contains(t, output, d.verdict)
	}
}

func TestAuditLoggerDoesNotPanicWithNilLogger(t *testing.T) {
	pal := &PolicyAuditLogger{
		logger:   nil,
		logLevel: slog.LevelInfo,
	}

	// Should not panic
	assert.NotPanics(t, func() {
		pal.LogDecision(1000, "policy", "ALLOW", "test")
	})

	assert.NotPanics(t, func() {
		pal.LogEvaluation(context.Background(), "policy-key", nil, "result")
	})
}

func TestGetLogLevelThreadSafety(t *testing.T) {
	pal := NewPolicyAuditLogger(slog.Default(), slog.LevelInfo)

	// Simulate concurrent access
	done := make(chan slog.Level, 10)
	for i := 0; i < 10; i++ {
		go func() {
			level := pal.GetLogLevel()
			done <- level
		}()
	}

	// Wait for all goroutines
	for i := 0; i < 10; i++ {
		level := <-done
		assert.Equal(t, slog.LevelInfo, level)
	}
}

func TestLogDecisionWithVariousIdentities(t *testing.T) {
	buf := new(bytes.Buffer)
	opts := &slog.HandlerOptions{Level: slog.LevelDebug}
	handler := slog.NewTextHandler(buf, opts)
	logger := slog.New(handler)

	pal := NewPolicyAuditLogger(logger, slog.LevelInfo)

	identities := []identity.NumericIdentity{
		identity.NumericIdentity(0),
		identity.NumericIdentity(1),
		identity.NumericIdentity(1000),
		identity.NumericIdentity(0xFFFFFFFF),
	}

	for _, id := range identities {
		pal.LogDecision(id, "test-policy", "ALLOW", "test")
	}

	output := buf.String()
	assert.NotEmpty(t, output)
	assert.Contains(t, output, "policy decision")
}

